const message = $input.first().json.body?.message || '';

if (!message || message.trim().length === 0) {
  throw new Error('Message field is required');
}

if (message.length > 5000) {
  throw new Error('Message too long (max 5000 characters)');
}

return [{ json: { message: message.trim(), receivedAt: new Date().toISOString() } }];

const rawResponse = $input.first().json.message?.content || $input.first().json.text || '';

let parsed;
try {
  // Strip any accidental markdown code fences
  const cleaned = rawResponse.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback if JSON parse fails
  parsed = {
    intent: 'Support',
    name: null,
    company: null,
    requirement: null,
    ai_response: 'Thank you for reaching out. Our team will get back to you within 24 hours.',
    parse_error: e.message
  };
}

// Validate intent is one of allowed values
const allowed = ['Sales', 'Support', 'Spam'];
if (!allowed.includes(parsed.intent)) {
  parsed.intent = 'Support';
}

return [{ json: { ...parsed, raw_message: $('Validate Input').first().json.message } }];
